// lv_image_header_t is a bit-field struct (NOT a sequence of plain
// uint32_t fields). The little-endian layout is:
//   byte 0   : magic       (8 bits)  = 0x19
//   byte 1   : cf          (8 bits)  = LV_COLOR_FORMAT_ARGB8888
//   bytes 2-3: flags       (16 bits) = 0
//   bytes 4-5: w           (16 bits) = MIC_ICON_W
//   bytes 6-7: h           (16 bits) = MIC_ICON_H
//   bytes 8-9: stride      (16 bits) = MIC_ICON_W * 4 (ARGB8888 bpp)
//   bytes 10-11: reserved  (16 bits) = 0
// Use designated initializers by FIELD NAME so the order is correct
// regardless of the underlying bit packing.
static const lv_image_header_t mic_icon_header = {
    .magic      = LV_IMAGE_HEADER_MAGIC,
    .cf         = LV_COLOR_FORMAT_ARGB8888,
    .flags      = 0,
    .w          = MIC_ICON_W,
    .h          = MIC_ICON_H,
    .stride     = MIC_ICON_W * 4,
    .reserved_2 = 0,
};

// Positional initializer for lv_image_dsc_t (struct field order:
// header, data_size, data — not a bit field, safe positional).
static const lv_image_dsc_t mic_icon = {
    mic_icon_header,
    MIC_ICON_BYTES,
    mic_icon_data,
};

LV_IMAGE_DECLARE(mic_icon);